package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.io.File;
import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.RDF;
import org.eclipse.rdf4j.query.TupleQueryResult;
import org.eclipse.rdf4j.repository.Repository;
import org.eclipse.rdf4j.repository.RepositoryConnection;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbDistinctStableOrderTest {

	private final ValueFactory vf = SimpleValueFactory.getInstance();

	private Repository repo;

	@BeforeEach
	void before(@TempDir File dataDir) {
		repo = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("psoc,posc")));
		repo.init();

		IRI type1 = vf.createIRI("urn:type1");
		IRI type2 = vf.createIRI("urn:type2");

		try (RepositoryConnection connection = repo.getConnection()) {
			connection.add(vf.createIRI("urn:s1"), RDF.TYPE, type1);
			connection.add(vf.createIRI("urn:s2"), RDF.TYPE, type1);
			connection.add(vf.createIRI("urn:s3"), RDF.TYPE, type2);
			connection.add(vf.createIRI("urn:s4"), RDF.TYPE, type2);
		}
	}

	@Test
	void testDistinctTypeRemainsCorrectOnDuplicateHeavyData() {
		assertEquals(List.of("urn:type1", "urn:type2"),
				evaluate("select distinct ?type where { ?a a ?type. } order by ?type", "type"));
	}

	@Test
	void testDistinctAliasRemainsCorrect() {
		assertEquals(List.of("urn:s1", "urn:s2", "urn:s3", "urn:s4"),
				evaluate("select distinct ?x where { ?a a ?type. bind(?a as ?x) } order by ?x", "x"));
	}

	@Test
	void testDistinctOrderLimitRewriteRemainsCorrect() {
		assertEquals(List.of("urn:type1"),
				evaluate("select distinct ?type where { ?a a ?type. } order by ?type limit 1", "type"));
	}

	@Test
	void testDistinctComputedAliasFallsBackButStaysCorrect() {
		assertEquals(List.of("urn:s1", "urn:s2", "urn:s3", "urn:s4"),
				evaluate("select distinct ?x where { ?a a ?type. bind(str(?a) as ?x) } order by ?x", "x"));
	}

	@AfterEach
	void after() {
		repo.shutDown();
	}

	private List<String> evaluate(String query, String bindingName) {
		try (RepositoryConnection connection = repo.getConnection();
				TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
			List<String> values = new ArrayList<>();
			while (result.hasNext()) {
				values.add(result.next().getValue(bindingName).stringValue());
			}
			return values;
		}
	}
}
